(function(){"use strict";const metaEl=document.getElementById("crm-staff-home-meta");let meta={};try{meta=JSON.parse(metaEl?.textContent||"{}");}catch{meta={};}
const statusLabels=meta.status_labels||{};const levelLabels=meta.level_labels||{};const sourceLabels=meta.source_labels||{};const kpiStatusLabels=meta.kpi_status_labels||{};function $(id){return document.getElementById(id);}
function esc(s){return String(s??"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;");}
async function reqJson(url){const res=await fetch(url,{credentials:"same-origin",headers:{Accept:"application/json"}});const data=await res.json().catch(()=>({}));if(!res.ok)throw new Error(data.error||`HTTP ${res.status}`);return data;}
function renderKpi(kpi){const statsEl=$("crm-staff-home-kpi-stats");const listEl=$("crm-staff-home-kpi-list");if(!statsEl||!listEl)return;const counts=kpi?.counts||{};statsEl.innerHTML=`
      <span class="crm-staff-home-stat"><strong>${kpi?.total || 0}</strong> chỉ tiêu</span>
      <span class="crm-staff-home-stat is-ok"><strong>${counts.achieved || 0}</strong> đạt</span>
      <span class="crm-staff-home-stat is-warn"><strong>${counts.at_risk || 0}</strong> cần chú ý</span>
    `;const items=Array.isArray(kpi?.items)?kpi.items:[];if(!items.length){listEl.innerHTML='<li class="muted">Chưa có chỉ tiêu KPI tháng này.</li>';return;}
listEl.innerHTML=items.map((row)=>{const st=row.status||"draft";const cls=st==="achieved"?"is-ok":st==="at_risk"||st==="missed"?"is-warn":"";const actual=row.actual_value!=null&&row.actual_value!==""?row.actual_value:"—";const target=row.target_value!=null&&row.target_value!==""?row.target_value:"—";return`<li class="crm-staff-home-list-item ${cls}">
          <span class="crm-staff-home-list-title">${esc(row.metric_name)}</span>
          <span class="crm-staff-home-list-meta">${esc(actual)} / ${esc(target)} ${esc(row.unit || "")} · ${esc(row.status_label || kpiStatusLabels[st] || st)}</span>
        </li>`;}).join("");}
function renderLeads(leads){const statsEl=$("crm-staff-home-lead-stats");const listEl=$("crm-staff-home-leads-list");if(!statsEl||!listEl)return;const st=leads?.stats||{};statsEl.innerHTML=`
      <span class="crm-staff-home-stat"><strong>${st.total || 0}</strong> lead</span>
      <span class="crm-staff-home-stat is-ok"><strong>${st.won || 0}</strong> chốt</span>
      <span class="crm-staff-home-stat is-warn"><strong>${st.sla_overdue || 0}</strong> quá SLA</span>
    `;const items=Array.isArray(leads?.recent)?leads.recent:[];if(!items.length){listEl.innerHTML='<li class="muted">Chưa có lead được phân công.</li>';return;}
listEl.innerHTML=items.map((lead)=>{const src=sourceLabels[lead.source]||lead.source||"—";const lvl=levelLabels[lead.lead_level]||lead.lead_level||"";const stLabel=statusLabels[lead.status]||lead.status||"";return`<li class="crm-staff-home-list-item">
          <a href="/crm/leads" class="crm-staff-home-list-link">
            <span class="crm-staff-home-list-title">${esc(lead.full_name || "Lead")} · #${esc(String(lead.id || ""))}</span>
            <span class="crm-staff-home-list-meta">${esc(src)} · ${esc(lead.phone || lead.email || "—")}${lvl ? `· ${esc(lvl)}` : ""}${stLabel ? `· ${esc(stLabel)}` : ""}</span>
          </a>
        </li>`;}).join("");}
function renderReport(report){const box=$("crm-staff-home-report-box");if(!box)return;const today=report?.today||"";if(report?.submitted&&report.report){const r=report.report;const summary=(r.summary||"").trim();box.innerHTML=`
        <p class="crm-staff-home-report-ok">✓ Đã nộp báo cáo ngày <strong>${esc(today)}</strong></p>
        <p class="crm-staff-home-report-summary">${esc(summary.slice(0, 200))}${summary.length > 200 ? "…" : ""}</p>
        <a class="btn-secondary btn-sm" href="/crm/daily-reports">Xem / sửa báo cáo</a>`;box.classList.remove("muted");return;}
box.innerHTML=`
      <p class="crm-staff-home-report-missing">Chưa nộp báo cáo ngày <strong>${esc(today)}</strong>.</p>
      <a class="btn-primary btn-sm" href="/crm/daily-reports">Nhập báo cáo ngay</a>`;box.classList.remove("muted");}
async function init(){const sub=$("crm-staff-home-sub");try{const data=await reqJson("/api/crm/staff/dashboard");const staff=data.staff||{};const workload=data.workload||{};if(sub){const parts=[];if(staff.position_name)parts.push(staff.position_name);if(workload.open_cases)parts.push(`${workload.open_cases} case đang mở`);if(workload.active_customers)parts.push(`${workload.active_customers} khách hàng`);sub.textContent=parts.length?parts.join(" · "):"Theo dõi KPI, Lead được phân công và báo cáo công việc hàng ngày.";}
renderKpi(data.kpi);renderLeads(data.leads);renderReport(data.daily_report);}catch(e){if(sub)sub.textContent="Không tải được tổng quan.";const grid=$("crm-staff-home-grid");if(grid){grid.innerHTML=`<div class="crm-form-msg is-error">${esc(e instanceof Error ? e.message : "Lỗi tải dữ liệu")}</div>`;}}}
init();})();